"use client";
import React from "react";
import { Github, ExternalLink } from "lucide-react";

interface ProjectCardProps {
  name: string;
  desc: string;
  type: string;
  gradientFrom: string;
  gradientTo: string;
  icon: React.ReactNode;
  link?: string;
  github?: string;
}

export function ProjectCard({
  name,
  desc,
  type,
  gradientFrom,
  gradientTo,
  icon,
  link,
  github,
}: ProjectCardProps) {
  // We use inline styles for the dynamic background gradients to keep the CSS reusable
  const cardGradient = `linear-gradient(135deg, ${gradientFrom} 0%, ${gradientTo} 100%)`;

  // We also tint the circles based on the primary gradient color with low opacity
  const circleBg = gradientFrom.replace(")", ", 0.2)").replace("rgb", "rgba");

  return (
    <div className="uiverse-parent">
      <div className="uiverse-card" style={{ background: cardGradient }}>
        <div className="uiverse-logo">
          <span className="uiverse-circle uiverse-circle1" style={{ background: circleBg }}></span>
          <span className="uiverse-circle uiverse-circle2" style={{ background: circleBg }}></span>
          <span className="uiverse-circle uiverse-circle3" style={{ background: circleBg }}></span>
          <span className="uiverse-circle uiverse-circle4" style={{ background: circleBg }}></span>
          <span className="uiverse-circle uiverse-circle5">
            {icon}
          </span>
        </div>

        <div className="uiverse-glass"></div>

        <div className="uiverse-content flex flex-col h-full">
          <span className="text-xs font-bold tracking-wider uppercase text-white/50 mb-2">{type}</span>
          <span className="uiverse-title">{name}</span>
          <span className="uiverse-text line-clamp-4">{desc}</span>
        </div>

        <div className="uiverse-bottom">
          <div className="uiverse-social-buttons">
            {github && (
              <a href={github} target="_blank" rel="noopener noreferrer" className="uiverse-social-btn hover-bg-dark">
                <Github size={16} className="uiverse-svg" />
              </a>
            )}
            {link && (
              <a href={link} target="_blank" rel="noopener noreferrer" className="uiverse-social-btn hover-bg-dark">
                <ExternalLink size={16} className="uiverse-svg" />
              </a>
            )}
          </div>

          <div className="uiverse-view-more cursor-pointer">
            <span className="uiverse-view-more-btn">View more</span>
            <svg
              className="uiverse-svg-arrow"
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 24 24"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="m6 9 6 6 6-6"></path>
            </svg>
          </div>
        </div>
      </div>
    </div>
  );
}
